from flask import Flask, request, jsonify
import jwt
import requests
import os

app = Flask(__name__)

BACKEND_SERVICE_URL = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:5001')

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def validate_and_extract_claims(token):
    try:
        decoded = jwt.decode(token, options={"verify_signature": True}, algorithms=["HS256", "RS256"], key=os.environ.get('JWT_SECRET', 'your-secret-key'))
        return decoded
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway(path):
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'Missing authorization token'}), 401
    
    claims = validate_and_extract_claims(token)
    
    if not claims:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    headers = {
        'X-User-Id': str(claims.get('user_id', '')),
        'X-User-Email': str(claims.get('email', '')),
        'X-User-Role': str(claims.get('role', '')),
        'Content-Type': request.headers.get('Content-Type', 'application/json')
    }
    
    backend_url = f"{BACKEND_SERVICE_URL}/{path}"
    
    try:
        if request.method == 'GET':
            response = requests.get(backend_url, headers=headers, params=request.args, timeout=30)
        elif request.method == 'POST':
            response = requests.post(backend_url, headers=headers, json=request.get_json(), timeout=30)
        elif request.method == 'PUT':
            response = requests.put(backend_url, headers=headers, json=request.get_json(), timeout=30)
        elif request.method == 'DELETE':
            response = requests.delete(backend_url, headers=headers, timeout=30)
        elif request.method == 'PATCH':
            response = requests.patch(backend_url, headers=headers, json=request.get_json(), timeout=30)
        
        return jsonify(response.json()), response.status_code
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service unavailable'}), 503

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)